// package.json dependencies:
// "@google-cloud/secret-manager": "^5.0.0",
// "google-auth-library": "^9.0.0"

const { SecretManagerServiceClient } = require('@google-cloud/secret-manager');
const { GoogleAuth } = require('google-auth-library');

/**
 * Cloud Function using Workload Identity and short-lived tokens
 * Demonstrates secure secret access without service account keys
 */
exports.processSecureData = async (req, res) => {
  try {
    // Step 1: Initialize Google Auth with automatic ADC (Application Default Credentials)
    const auth = new GoogleAuth({
      scopes: ['https://www.googleapis.com/auth/cloud-platform'],
      // Use Workload Identity - no service account keys needed
      projectId: process.env.GCP_PROJECT
    });

    // Step 2: Get short-lived access token (automatically refreshed)
    const client = await auth.getClient();
    const accessTokenResponse = await client.getAccessToken();

    console.log('Token expiry:', accessTokenResponse.res?.data?.expires_in || '3600s');

    // Step 3: Access Secret Manager with least-privilege permissions
    const secretClient = new SecretManagerServiceClient({ auth });

    // Use resource-based IAM condition for time-based access
    const secretName = `projects/${process.env.GCP_PROJECT}/secrets/db-password/versions/latest`;

    const [version] = await secretClient.accessSecretVersion({
      name: secretName,
    });

    const secretValue = version.payload.data.toString('utf8');

    // Step 4: Implement token validation and rotation
    const tokenMetadata = await client.getTokenInfo(accessTokenResponse.token);

    if (tokenMetadata.expiry_date < Date.now() + 300000) { // 5 min buffer
      console.log('Token expiring soon, refreshing...');
      await client.refreshAccessToken();
    }

    // Step 5: Use secret securely (example: database connection)
    // DO NOT log or expose secret value
    const dbConnection = await connectToDatabase(secretValue);

    res.status(200).json({ 
      status: 'success',
      message: 'Data processed securely'
    });

  } catch (error) {
    console.error('Security error:', error.message);
    res.status(500).json({ 
      error: 'Internal server error',
      // DO NOT expose error details in production
    });
  }
};

